const API_BASE = "http://127.0.0.1:8000";

export function getToken() {
  return localStorage.getItem("token");
}

export function setToken(t) {
  localStorage.setItem("token", t);
}

export function clearToken() {
  localStorage.removeItem("token");
}

async function request(path, { method = "GET", body = null, isForm = false } = {}) {
  const headers = {};
  const token = getToken();
  if (token) headers["Authorization"] = `Bearer ${token}`;
  if (!isForm) headers["Content-Type"] = "application/json";

  const res = await fetch(`${API_BASE}${path}`, {
    method,
    headers,
    body: body ? (isForm ? body : JSON.stringify(body)) : null
  });

  const data = await res.json().catch(() => ({}));
  if (!res.ok) {
    throw new Error(data.detail || "Request failed");
  }
  return data;
}

export const api = {
  signup: (payload) => request("/auth/signup", { method: "POST", body: payload }),
  login: (payload) => request("/auth/login", { method: "POST", body: payload }),
  me: () => request("/me"),
  updateMe: (payload) => request("/me", { method: "PUT", body: payload }),

  listInventory: () => request("/inventory"),
  addItem: (payload) => request("/inventory", { method: "POST", body: payload }),
  updateItem: (id, payload) => request(`/inventory/${id}`, { method: "PUT", body: payload }),
  deleteItem: (id) => request(`/inventory/${id}`, { method: "DELETE" }),

  quickAdd: (text) => request("/ai/quick-add", { method: "POST", body: { text } }),
  barcodeLookup: (barcode) => request("/ai/barcode-lookup", { method: "POST", body: { barcode } }),

  ocrReceipt: (file) => {
    const fd = new FormData();
    fd.append("file", file);
    return request("/ai/ocr-receipt", { method: "POST", body: fd, isForm: true });
  },
  ocrCommit: (items) => request("/ai/ocr-commit", { method: "POST", body: items }),

  getRecipes: () => request("/ai/recipes")
};
